INSERT INTO questions (question_text, choices, correct_answer, explanation, subject, topic, difficulty, exam_type) VALUES
('Who wrote the play "Romeo and Juliet"?', '["William Shakespeare", "Christopher Marlowe", "John Milton", "Geoffrey Chaucer"]', 'A', 'Romeo and Juliet was written by William Shakespeare, likely composed between 1594 and 1596.', 'English', 'World Literature', 'easy', 'secondary'),
('In Greek mythology, who was the king of the gods?', '["Zeus", "Poseidon", "Apollo", "Ares"]', 'A', 'Zeus was the king of the Olympian gods in Greek mythology, ruling from Mount Olympus.', 'English', 'World Literature', 'easy', 'secondary'),
('What is the epic poem written by Homer that tells the story of the Trojan War?', '["Iliad", "Odyssey", "Aeneid", "Beowulf"]', 'A', 'The Iliad is Homer''s epic poem about the Trojan War, focusing on the wrath of Achilles.', 'English', 'World Literature', 'easy', 'secondary'),
('In Shakespeare''s "Hamlet," what is the name of Hamlet''s father''s ghost?', '["King Hamlet", "King Claudius", "King Lear", "King Duncan"]', 'A', 'The ghost in Hamlet is the spirit of King Hamlet, Hamlet''s murdered father, who reveals the truth of his murder.', 'English', 'World Literature', 'medium', 'secondary'),
('Which novel by Miguel de Cervantes features the character Don Quixote?', '["Don Quixote", "The Alchemist", "One Hundred Years of Solitude", "Love in the Time of Cholera"]', 'A', 'Don Quixote (1605/1615) by Miguel de Cervantes is considered the first modern novel and features the idealistic knight Don Quixote.', 'English', 'World Literature', 'easy', 'secondary'),
('What literary device is used when non-human things are given human qualities?', '["Personification", "Metaphor", "Simile", "Alliteration"]', 'A', 'Personification is the literary device where non-human things (objects, animals, nature) are given human characteristics or qualities.', 'English', 'Literary Devices', 'easy', 'secondary'),
('Which Greek tragedy by Sophocles features a king who unknowingly kills his father and marries his mother?', '["Oedipus Rex", "Antigone", "Electra", "Medea"]', 'A', 'Oedipus Rex by Sophocles is the tragedy of Oedipus who fulfills the prophecy of killing his father Laius and marrying his mother Jocasta.', 'English', 'World Literature', 'medium', 'secondary'),
('In the context of reading, what is the "main idea" of a passage?', '["The central point the author wants to convey", "The first sentence of the passage", "A supporting detail in the text", "The conclusion of the passage"]', 'A', 'The main idea is the central point or most important thought that the author wants to communicate about a topic.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('What is the term for a conclusion drawn from evidence in a text that is not directly stated?', '["Inference", "Summary", "Paraphrase", "Quotation"]', 'A', 'An inference is a logical conclusion drawn from clues or evidence in the text, even though the information is not explicitly stated.', 'English', 'Reading Comprehension', 'medium', 'secondary'),
('Which of the following best describes the "tone" of a literary work?', '["The author''s attitude toward the subject", "The theme of the story", "The sequence of events", "The setting of the story"]', 'A', 'Tone refers to the author''s attitude toward the subject matter or audience, conveyed through word choice and style.', 'English', 'Reading Comprehension', 'medium', 'secondary'),
('Homer''s "Odyssey" tells the story of which hero''s journey home after the Trojan War?', '["Odysseus", "Achilles", "Hector", "Ajax"]', 'A', 'The Odyssey follows Odysseus (Ulysses in Latin) on his long journey home to Ithaca after the Trojan War.', 'English', 'World Literature', 'easy', 'secondary'),
('What is the term for the repetition of initial consonant sounds in nearby words?', '["Alliteration", "Assonance", "Onomatopoeia", "Consonance"]', 'A', 'Alliteration is the repetition of the same initial consonant sound in closely connected words, e.g., "Peter Piper picked."', 'English', 'Literary Devices', 'easy', 'secondary'),
('Which Shakespeare play contains the famous soliloquy beginning "To be, or not to be"?', '["Hamlet", "Macbeth", "Othello", "King Lear"]', 'A', 'The "To be, or not to be" soliloquy appears in Act 3, Scene 1 of Shakespeare''s Hamlet.', 'English', 'World Literature', 'easy', 'secondary'),
('In reading comprehension, what does "author''s purpose" refer to?', '["The reason why the author wrote the text", "The setting of the story", "The characters in the text", "The plot summary"]', 'A', 'Author''s purpose refers to the reason or intention behind writing a text — to inform, entertain, persuade, or describe.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('Which novel by Leo Tolstoy depicts Russian society during Napoleon''s invasion?', '["War and Peace", "Anna Karenina", "The Brothers Karamazov", "Crime and Punishment"]', 'A', 'War and Peace (1869) by Leo Tolstoy depicts Russian society during Napoleon''s invasion of Russia in 1812.', 'English', 'World Literature', 'medium', 'secondary'),
('What literary term refers to a story within a story?', '["Frame narrative", "Flashback", "Foreshadowing", "Stream of consciousness"]', 'A', 'A frame narrative (also called frame story) is a literary technique where a main story contains a second story, creating a "story within a story."', 'English', 'Literary Devices', 'medium', 'secondary'),
('In poetry, what is a "stanza"?', '["A group of lines forming a unit", "A rhyming pair of lines", "The main subject of a poem", "The rhythm pattern of a poem"]', 'A', 'A stanza is a group of lines in a poem that form a unit, similar to a paragraph in prose.', 'English', 'Literary Devices', 'easy', 'secondary'),
('Which French author wrote "Les Misérables"?', '["Victor Hugo", "Alexandre Dumas", "Gustave Flaubert", "Émile Zola"]', 'A', 'Les Misérables (1862) was written by Victor Hugo, depicting the struggles of ex-convict Jean Valjean in post-Napoleonic France.', 'English', 'World Literature', 'medium', 'secondary'),
('What is the term for the sequence of events in a story?', '["Plot", "Theme", "Setting", "Conflict"]', 'A', 'Plot is the sequence of events that make up a story, including the exposition, rising action, climax, falling action, and resolution.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('Which of these is an example of a simile?', '["Her eyes were like stars", "The wind howled", "Time is money", "The stars danced"]', 'A', 'A simile makes a comparison using "like" or "as." "Her eyes were like stars" is a simile because it uses the word "like."', 'English', 'Literary Devices', 'easy', 'secondary'),
('What is the narrative perspective when the story is told using "I" or "we"?', '["First person", "Second person", "Third person limited", "Third person omniscient"]', 'A', 'First-person narrative uses "I" or "we" to tell the story from the perspective of the narrator as a participant in the events.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('Which Russian author wrote "Crime and Punishment"?', '["Fyodor Dostoevsky", "Leo Tolstoy", "Anton Chekhov", "Ivan Turgenev"]', 'A', 'Crime and Punishment (1866) was written by Fyodor Dostoevsky, following the psychological torment of student Rodion Raskolnikov.', 'English', 'World Literature', 'medium', 'secondary'),
('In reading, what is a "context clue"?', '["Information in the surrounding text that helps determine word meaning", "A dictionary definition", "A footnote explanation", "A chapter summary"]', 'A', 'Context clues are words, phrases, or sentences near an unfamiliar word that help readers determine its meaning.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('What is the term for extreme exaggeration used for emphasis or effect?', '["Hyperbole", "Understatement", "Irony", "Sarcasm"]', 'A', 'Hyperbole is a figure of speech involving exaggeration for emphasis or humorous effect, e.g., "I''ve told you a million times."', 'English', 'Literary Devices', 'easy', 'secondary'),
('Which Shakespeare play features the character Iago as the villain?', '["Othello", "Hamlet", "Macbeth", "The Tempest"]', 'A', 'Iago is the manipulative villain in Shakespeare''s Othello, who plots against the Moorish general Othello out of jealousy.', 'English', 'World Literature', 'medium', 'secondary'),
('What is the term for the central message or universal truth of a literary work?', '["Theme", "Plot", "Setting", "Mood"]', 'A', 'Theme is the central message, moral, or universal truth that the author conveys throughout a literary work.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('In which country did the genre of "magical realism" primarily develop?', '["Latin America", "Eastern Europe", "West Africa", "Southeast Asia"]', 'A', 'Magical realism developed primarily in Latin America, associated with authors like Gabriel García Márquez, Jorge Luis Borges, and Isabel Allende.', 'English', 'World Literature', 'hard', 'secondary'),
('What is the term for a hint or clue about what will happen later in a story?', '["Foreshadowing", "Flashback", "Irony", "Symbolism"]', 'A', 'Foreshadowing is a literary technique where the author provides clues or hints about events that will occur later in the narrative.', 'English', 'Literary Devices', 'easy', 'secondary'),
('Gabriel García Márquez''s "One Hundred Years of Solitude" belongs to which literary genre?', '["Magical Realism", "Gothic Fiction", "Historical Fiction", "Science Fiction"]', 'A', '"One Hundred Years of Solitude" is the landmark work of magical realism, blending realistic narrative with magical elements.', 'English', 'World Literature', 'medium', 'secondary'),
('Which of the following best describes "irony"?', '["A contrast between what is expected and what actually happens", "A comparison using like or as", "The repetition of a sound", "A reference to another work"]', 'A', 'Irony involves a contrast or discrepancy between what is stated and what is meant, or between what is expected and what occurs.', 'English', 'Literary Devices', 'medium', 'secondary'),
('In a reading passage, what is the purpose of a "topic sentence"?', '["To state the main idea of a paragraph", "To conclude the paragraph", "To provide supporting evidence", "To introduce a new character"]', 'A', 'A topic sentence states the main idea or controlling idea of a paragraph, usually appearing at the beginning.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('Which of the following is an epic poem from ancient Mesopotamia?', '["The Epic of Gilgamesh", "The Iliad", "The Aeneid", "Paradise Lost"]', 'A', 'The Epic of Gilgamesh is one of the oldest works of literature, originating from ancient Mesopotamia (modern-day Iraq), dating to around 2100 BCE.', 'English', 'World Literature', 'medium', 'secondary'),
('What is the term for a reference to a well-known person, place, event, or work within a literary text?', '["Allusion", "Illusion", "Allegory", "Analogy"]', 'A', 'An allusion is an indirect reference to a historical event, person, place, or work of art/literature that readers are expected to recognize.', 'English', 'Literary Devices', 'medium', 'secondary'),
('In "Animal Farm" by George Orwell, the pigs'' rule is an allegory for which political system?', '["Totalitarianism/Stalinism", "Capitalism", "Democracy", "Feudalism"]', 'A', 'Animal Farm is an allegory for Stalinist Soviet Union, with Napoleon representing Stalin and the pigs'' corruption representing the Soviet leadership.', 'English', 'World Literature', 'medium', 'secondary'),
('Which reading skill involves restating information from a text in your own words?', '["Paraphrasing", "Summarizing", "Inferring", "Evaluating"]', 'A', 'Paraphrasing is restating information from a text in your own words while maintaining the original meaning, usually at similar length.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('What is the highest point of tension or conflict in a story called?', '["Climax", "Resolution", "Rising action", "Exposition"]', 'A', 'The climax is the highest point of tension, excitement, or conflict in a story — the turning point where events begin to resolve.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('Which author wrote "The Divine Comedy," featuring Dante''s journey through Hell, Purgatory, and Heaven?', '["Dante Alighieri", "Petrarch", "Boccaccio", "Virgil"]', 'A', 'The Divine Comedy was written by Dante Alighieri (1265–1321), an Italian poet whose work Inferno depicts a journey through the afterlife.', 'English', 'World Literature', 'medium', 'secondary'),
('What is the term for the atmosphere or emotional feeling of a literary work?', '["Mood", "Tone", "Theme", "Conflict"]', 'A', 'Mood is the atmosphere or emotional feeling that the author creates for the reader, while tone refers to the author''s attitude.', 'English', 'Literary Devices', 'medium', 'secondary'),
('Which type of conflict involves a character struggling against their own nature or conscience?', '["Character vs. self", "Character vs. nature", "Character vs. society", "Character vs. character"]', 'A', 'Character vs. self (internal conflict) involves a character''s internal struggle with their own emotions, desires, beliefs, or conscience.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('What is the term for a poem that mourns or laments someone who has died?', '["Elegy", "Ode", "Sonnet", "Ballad"]', 'A', 'An elegy is a poem of mourning, typically written to lament the death of a person and reflect on loss and mortality.', 'English', 'Literary Devices', 'medium', 'secondary'),
('In reading comprehension, which strategy involves previewing headings, pictures, and key words before reading?', '["Skimming", "Scanning", "Summarizing", "Predicting"]', 'A', 'Skimming involves quickly reading through a text, looking at headings, first/last sentences, and key words to get the general idea before reading in depth.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('Which novel by Charles Dickens features the orphan Oliver Twist?', '["Oliver Twist", "Great Expectations", "A Tale of Two Cities", "David Copperfield"]', 'A', 'Oliver Twist (1837–1839) by Charles Dickens tells the story of orphan Oliver Twist, highlighting social injustice in Victorian England.', 'English', 'World Literature', 'easy', 'secondary'),
('What is the term for a word that imitates the sound it represents?', '["Onomatopoeia", "Alliteration", "Assonance", "Consonance"]', 'A', 'Onomatopoeia refers to words that phonetically imitate or suggest the sound they describe, such as "buzz," "hiss," or "clang."', 'English', 'Literary Devices', 'easy', 'secondary'),
('In "The Great Gatsby" by F. Scott Fitzgerald, what does the green light symbolize?', '["Gatsby''s dreams and aspirations", "Danger and jealousy", "Money and wealth", "Nature and renewal"]', 'A', 'The green light at the end of Daisy''s dock symbolizes Gatsby''s hopes and dreams — his desire to recapture the past and achieve his idealized future.', 'English', 'World Literature', 'hard', 'secondary'),
('What is a "thesis statement" in an essay?', '["The main argument or central claim of the essay", "The opening sentence of the introduction", "A supporting example from the text", "The concluding thought of the essay"]', 'A', 'A thesis statement presents the main argument or central claim of an essay, typically appearing at the end of the introduction paragraph.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('Which literary device involves using a part to represent a whole or vice versa?', '["Synecdoche", "Metonymy", "Allegory", "Paradox"]', 'A', 'Synecdoche is a figure of speech in which a part represents the whole ("all hands on deck" using "hands" for people) or the whole represents a part.', 'English', 'Literary Devices', 'hard', 'secondary'),
('Which African author won the Nobel Prize in Literature in 1986?', '["Wole Soyinka", "Chinua Achebe", "Ngugi wa Thiong''o", "Nadine Gordimer"]', 'A', 'Wole Soyinka of Nigeria became the first African writer to win the Nobel Prize in Literature in 1986.', 'English', 'World Literature', 'hard', 'secondary'),
('In reading, what does "drawing conclusions" involve?', '["Using evidence from the text and prior knowledge to make a judgment", "Copying phrases directly from the text", "Counting the main characters", "Identifying the setting"]', 'A', 'Drawing conclusions involves combining evidence from the text with prior knowledge to make a reasoned judgment not explicitly stated in the text.', 'English', 'Reading Comprehension', 'medium', 'secondary'),
('What is the term for a 14-line poem with a specific rhyme scheme, often associated with Shakespeare?', '["Sonnet", "Ode", "Villanelle", "Haiku"]', 'A', 'A sonnet is a 14-line poem with a specific rhyme scheme. The Shakespearean sonnet uses three quatrains and a couplet (ABAB CDCD EFEF GG).', 'English', 'Literary Devices', 'medium', 'secondary'),
('Which reading strategy involves looking for specific information in a text without reading every word?', '["Scanning", "Skimming", "Summarizing", "Annotating"]', 'A', 'Scanning involves moving the eyes quickly through a text to locate specific information, facts, or key words without reading everything.', 'English', 'Reading Comprehension', 'easy', 'secondary'),
('In "To Kill a Mockingbird" by Harper Lee, what theme is most prominently explored?', '["Racial injustice and moral courage", "Coming-of-age and romance", "War and heroism", "Nature and survival"]', 'A', '"To Kill a Mockingbird" explores racial injustice in the American South through the eyes of Scout Finch, whose father Atticus defends a wrongly accused Black man.', 'English', 'World Literature', 'medium', 'secondary');
